import{_ as t,o as r,c as a,ae as s}from"./chunks/framework.BeVX27ge.js";const m=JSON.parse('{"title":"User Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/admin-users.md","filePath":"en/admin-users.md"}'),o={name:"en/admin-users.md"};function i(n,e,l,u,c,g){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="user-management" tabindex="-1">User Management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User Management&quot;">​</a></h1><blockquote><p>Manage platform accounts, roles, and permissions to control feature access.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>User management is the core feature of the admin panel, allowing you to create, edit, import, and delete user accounts, as well as assign appropriate roles and permissions.</p><blockquote><p>This feature is only available to administrators with User Management permissions.</p></blockquote><h2 id="how-to-access" tabindex="-1">How to Access <a class="header-anchor" href="#how-to-access" aria-label="Permalink to &quot;How to Access&quot;">​</a></h2><ol><li>Click the <strong>Settings Icon</strong> (Gear) in the top right corner of the page.</li><li>Select &quot;User Management&quot; in the admin panel.</li></ol><hr><h2 id="page-structure" tabindex="-1">Page Structure <a class="header-anchor" href="#page-structure" aria-label="Permalink to &quot;Page Structure&quot;">​</a></h2><ul><li><strong>Title Bar</strong>: Includes Filters, Add User, and More Actions menu.</li><li><strong>Filter Tags</strong>: Displays currently applied filters.</li><li><strong>User Table</strong>: List of all users.</li><li><strong>Pagination</strong>: Page navigation.</li></ul><hr><h2 id="filtering-users" tabindex="-1">Filtering Users <a class="header-anchor" href="#filtering-users" aria-label="Permalink to &quot;Filtering Users&quot;">​</a></h2><p>Click the <strong>&quot;Filters&quot;</strong> button to open the filter panel:</p><ul><li><strong>Company</strong>: Filter by associated company.</li><li><strong>Department</strong>: Filter by department (requires selecting Company first).</li><li><strong>Role</strong>: Admin / User / Superuser / Supervisor.</li><li><strong>Email</strong>: Text search.</li><li><strong>Name</strong>: Text search.</li><li><strong>Status</strong>: Active / Disabled.</li></ul><hr><h2 id="adding-users" tabindex="-1">Adding Users <a class="header-anchor" href="#adding-users" aria-label="Permalink to &quot;Adding Users&quot;">​</a></h2><p>Click <strong>&quot;Add User&quot;</strong> to open the creation form.</p><ul><li><strong>Name</strong>: Display name (Required if Email is provided).</li><li><strong>Email</strong>: Login account (Required or Emp No).</li><li><strong>Emp No</strong>: Employee number.</li><li><strong>Company</strong>: Select company (Required).</li><li><strong>Department</strong>: Select department.</li><li><strong>Role</strong>: Assign role.</li><li><strong>Status</strong>: Toggle Active/Disabled.</li></ul><h3 id="roles-description" tabindex="-1">Roles Description <a class="header-anchor" href="#roles-description" aria-label="Permalink to &quot;Roles Description&quot;">​</a></h3><ul><li><strong>Admin</strong>: Full access to all management features.</li><li><strong>Superuser</strong>: Advanced access with limited management capabilities.</li><li><strong>Supervisor</strong>: Can monitor team practice data but cannot modify system settings.</li><li><strong>User</strong>: General user, can only access practice, history, and evaluations.</li></ul><hr><h2 id="other-features" tabindex="-1">Other Features <a class="header-anchor" href="#other-features" aria-label="Permalink to &quot;Other Features&quot;">​</a></h2><ul><li><strong>Edit User</strong>: Click &quot;Edit&quot; in the table to modify details.</li><li><strong>Delete User</strong>: Click &quot;Delete&quot;. This performs a soft delete (account cannot log in).</li><li><strong>Batch Import</strong>: Use a CSV template to add multiple users at once.</li><li><strong>Batch Delete</strong>: Select multiple users and delete them simultaneously.</li></ul>',23)])])}const h=t(o,[["render",i]]);export{m as __pageData,h as default};
